var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"조립은 끝났어.","JPN":"組み立ては終わったよ。","ENG":"It's finished. The assembly is complete.","TWN":"組裝已經完成了。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_MEMORY","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"마왕 타기리온.","JPN":"魔王タギリオン。","ENG":"Demon Lord Thagirion.","TWN":"魔王塔基里翁。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_MEMORY","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DOLL_ANAP_NO_NAME","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_MEMORY","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":{"char_id":"DOLL_ANAP_NO_NAME","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"DOLL_ANAP_NO_NAME","text":{"KOREA":"이 모습은...?","JPN":"この姿は……？","ENG":"This form...?","TWN":"這個是……？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_MEMORY","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":{"char_id":"DOLL_ANAP_NO_NAME","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"기억나? 우리가 가장 행복했던 어린 시절의 모습을.","JPN":"覚えてる？　私たちが一番幸せだった、子どもの頃の姿。","ENG":"Do you remember? The way we looked as children, back when we were happiest.","TWN":"你還記得嗎？我們最幸福的童年模樣。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_MEMORY","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"DOLL_ANAP_NO_NAME","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"DOLL_ANAP_NO_NAME","text":{"KOREA":"...그래. 기억나.","JPN":"……うん、覚えてる。","ENG":"...Yes. I remember.","TWN":"……是的，我記得。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_MEMORY","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"DOLL_ANAP_NO_NAME","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"DOLL_ANAP_NO_NAME","text":{"KOREA":"처음으로 인형을 자랑했더니, 언니는 이렇게 예쁘면 팔아도 되겠다는 말을 했었지.","JPN":"初めて作った人形を自慢したら、お姉ちゃんは売り物にできるほど可愛いと言ってくれたよね。","ENG":"When I showed you the doll I made for the first time, you said it was so beautiful I could probably sell it.","TWN":"我第一次誇獎那個人偶，結果姐姐說這麼漂亮的話，應該也可以賣掉吧。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_MEMORY","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"DOLL_ANAP_NO_NAME","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"그래서 파는 게 아니라 생일선물이라고 했더니, 화들짝 놀라면서 당황했잖아.","JPN":"それで売り物じゃなくて誕生日プレゼントって言ったら、びっくりして慌ててた。","ENG":"So I told you it wasn't for sale. It was a birthday present. You were so startled and flustered.","TWN":"所以你不是嚇了一跳，慌張地說那不是要賣的，而是生日禮物嗎？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_MEMORY","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":{"char_id":"DOLL_ANAP_NO_NAME","face":"UNIT_LAUGH"}}}},{"id":"L10_1","type":"dialog","speaker":"DOLL_ANAP_NO_NAME","text":{"KOREA":"...언니는 그런 모습, 원래 잘 안 보여주는데 말이야.","JPN":"……お姉ちゃんはそんな姿、めったに見せないのに。","ENG":"...You don't usually show that side of yourself.","TWN":"……姐姐本來就很少露出那種表情。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_MEMORY","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":{"char_id":"DOLL_ANAP_NO_NAME","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"그때... 인형을 팔아서 언니를 부자로 만들어줄거라 다짐하고 연습했는데...","JPN":"あの時……人形を売ってお姉ちゃんを大富豪にしてあげようと思って、頑張って練習したけど……","ENG":"Back then... I practiced because I promised I'd sell dolls and make you rich someday...","TWN":"那時……我曾下定決心要賣掉人偶，讓姐姐變得富有，還練習了很多次……"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_MEMORY","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"DOLL_ANAP_NO_NAME","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"널 만드는 데에 쓰게 될 줄은 몰랐네.","JPN":"その腕を、あなたを作るために使うことになるとは。","ENG":"I never thought I'd end up using those skills to make you.","TWN":"沒想到最後卻用在了創造你。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_MEMORY","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"DOLL_ANAP_NO_NAME","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"DOLL_ANAP_NO_NAME","text":{"KOREA":"그런 말하지 마.","JPN":"そんなこと言わないで。","ENG":"Don't say that.","TWN":"別那樣說。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_MEMORY","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"DOLL_ANAP_NO_NAME","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"DOLL_ANAP_NO_NAME","text":{"KOREA":"이 모습은, 지금까지 만든 그 어떤 인형보다 아름다워.","JPN":"この姿は、今まで作ったどの人形よりも美しいよ。","ENG":"This form is more beautiful than any doll I've ever made.","TWN":"這個樣子，比迄今製作的任何人偶都還要美麗。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_MEMORY","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"DOLL_ANAP_NO_NAME","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"...미안해. 너에게 이런 나쁜 역할을 맡겨서.","JPN":"……ごめんね。あなたにこんな悪役を任せてしまって。","ENG":"...I'm sorry. For making you take on such a terrible role.","TWN":"……對不起，讓你承擔這樣的角色。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_MEMORY","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"DOLL_ANAP_NO_NAME","face":"UNIT_LAUGH"}}}},{"id":"L16_1","type":"dialog","speaker":"DOLL_ANAP_NO_NAME","text":{"KOREA":"누군가는 운명을 받아들이고, 또 누군가는 과거의 순수함을 간직해야 하니까.","JPN":"誰かは運命を受け入れ、誰かは過去の純粋さを保っていないといけないから。","ENG":"Someone has to accept our fate, and someone else has to preserve the innocence we once had.","TWN":"因為有人必須接受命運，也有人必須保留過去的純真。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_MEMORY","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"DOLL_ANAP_NO_NAME","face":"UNIT_LAUGH"}}}},{"id":"L17_1","type":"dialog","speaker":"DOLL_ANAP_NO_NAME","text":{"KOREA":"먼 훗날, 우리의 운명을 정해준 그녀에게 복수하기 위해.","JPN":"遠い未来、私たちの運命を決めた彼女に復讐するために。","ENG":"So that one day, far in the future, we can take revenge on the one who decided our fate.","TWN":"為了在遙遠的未來，向決定我們命運的她復仇。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_MEMORY","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"DOLL_ANAP_NO_NAME","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_MEMORY","slots":{"L":null,"C":{"char_id":"DOLL_ANAP_NO_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DOLL_ANAP_NO_NAME","text":{"KOREA":"방금... 나에게 뭘 집어넣은 거야?","JPN":"今……私に何を入れたの？","ENG":"Just now... what did you put inside me?","TWN":"剛才……你在我的身體放了什麼？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_MEMORY","slots":{"L":null,"C":{"char_id":"DOLL_ANAP_NO_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"언니를 사랑하는 나의 마음.","JPN":"お姉ちゃんを愛する私の心。","ENG":"My love for you, sister.","TWN":"我對姐姐的愛。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_MEMORY","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DOLL_ANAP_NO_NAME","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_MEMORY","slots":{"L":null,"C":{"char_id":"DOLL_ANAP_NO_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DOLL_ANAP_NO_NAME","text":{"KOREA":"처음 각오와 다르잖아, 아우드라.","JPN":"最初の覚悟と違うじゃない、アウドラ。","ENG":"That's not what we agreed on, Audra.","TWN":"這和最初的覺悟不同啊，奧德拉。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_MEMORY","slots":{"L":null,"C":{"char_id":"DOLL_ANAP_NO_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DOLL_ANAP_NO_NAME","text":{"KOREA":"이런 순수하고 나약한 마음은... 나에게 필요 없어.","JPN":"こんな純粋で弱い心は……私には要らない。","ENG":"Such pure and fragile feelings... I don't need them.","TWN":"我不需要……這種純粹而脆弱的心。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_MEMORY","slots":{"L":null,"C":{"char_id":"DOLL_ANAP_NO_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"넌 아주 오랜 시간동안 마왕으로서... 우리와 같은 운명을 가진 다른 세계의 아이들을 죽이며, 외롭게 살아갈 거야.","JPN":"あなたはこれから長い時間を魔王として……私たちと同じ運命を持つ他の世界の子を殺しながら寂しく生きていく。","ENG":"For a very long time, you'll live on as a Demon Lord... Killing children from other worlds who share the same fate as us, all alone.","TWN":"你將在很長的時間裡，作為魔王活下去……殺死來自其他世界、與我們有相同命運的孩子們，孤獨地活著。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_MEMORY","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"적어도 우리 중 한 명은 그 아이들의 최후를 사랑으로 애도하며 눈물을 흘려줘야 하니까.","JPN":"せめて私たちのどちらかは、その子の最後を愛で追悼し、涙を流してあげないといけないから。","ENG":"At the very least, one of us should mourn their ends with love and shed tears for them.","TWN":"至少我們之中必須有一個人，要流淚哀悼那些孩子的結局。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_MEMORY","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"그러니까, 이 마음은 네가 간직해줬으면 좋겠어.","JPN":"だから、この心はあなたが持っていてほしい。","ENG":"So I want you to keep this feeling safe.","TWN":"所以，請你替我保留這份心意。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_MEMORY","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DOLL_ANAP_NO_NAME","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_MEMORY","slots":{"L":null,"C":{"char_id":"DOLL_ANAP_NO_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"만약... 내가 네가 준 이 마음을 더럽힐 만큼, 악의에 물든다면...","JPN":"もし……あなたがくれたこの心を汚すほど、私が悪意に染まったら……","ENG":"If... I become so consumed by evil that I defile the feelings you gave me...","TWN":"如果……有一天我被惡意侵蝕，玷汙了你給我的這份心意……"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_MEMORY","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"그땐, 네가 나를 멈춰줘.","JPN":"その時は、あなたが私を止めてね。","ENG":"Then you must stop me.","TWN":"那時候，就由你來阻止我。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_MEMORY","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"나는 널 죽이지 않아.","JPN":"私はあなたを殺さないよ。","ENG":"I won't kill you.","TWN":"我不會殺你。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_MEMORY","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"영겁이 흐른 먼 훗날, 가을의 끝무렵 즈음에... 우리는 다시 하나로 돌아갈 테니까.","JPN":"永劫の時が流れた遠い未来、晩秋頃……私たちは再び一つになるんだから。","ENG":"Far in the distant future, near the end of autumn after an eternity has passed... we will become one again.","TWN":"在遙遠的未來，當秋天走到盡頭時……我們會再次合而為一。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_MEMORY","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"보고 있어? 타기리온?","JPN":"見えてる？　タギリオン。","ENG":"Do you see it, Thagirion?","TWN":"看見了嗎，塔基里翁？"},"stage":{"bg":"MS_1606_2","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"그녀의 분신이 우리의 결실을 손에 쥐고... 우릴 이렇게 만든 자의 심장에 비수를 꽂는 광경이.","JPN":"彼女の分身が私たちが生み出した結実を手に取り……私たちをこんな目に遭わせた者の心臓を貫く光景が。","ENG":"The sight of her avatar holding the fruit we created in her hands... and driving a blade into the heart of the one who made us this way.","TWN":"她的分身手中握著我們創造的成果……將刀刃刺入將我們變成這樣的人的心臟。"},"stage":{"bg":"MS_1606_2","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};